const input1 = $input.all();
const allResults = [];

for (const item of input1) {
  const organic = item.json.organic || [];
  for (const r of organic) {
    allResults.push({
      title: r.title || '',
      link: r.link || '',
      snippet: r.snippet || '',
      date: r.date || 'unknown'
    });
  }
}

return [{ json: { jobs: allResults } }];

const jobs = $input.first().json.jobs;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'x-api-key': 'YOUR_ANTHROPIC_API_KEY',
    'anthropic-version': '2023-06-01',
    'content-type': 'application/json'
  },
  body: {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 1000,
    messages: [{
      role: 'user',
      content: 'You must respond with ONLY a JSON array. No backticks. No markdown. No code blocks. No explanation. Start your response with [ and end with ]. Example format: [{"title":"job","url":"http://example.com","score":75,"track":"A","reason":"good match"}]. Now score these jobs for Rakshith Ravi (Python PyTorch ROS2 ADAS Bavaria Werkstudent). Track A: ADAS CV ML. Track B: Technical PM. NO FIT: business HR pharma. Score 0-100. Jobs: ' + JSON.stringify(jobs)
    }]
  },
  json: true
});

return [{ json: response }];

const response = $input.first().json;
const text = response.content[0].text;

let jobs;
try {
  const start = text.indexOf('[');
  const end = text.lastIndexOf(']');
  let clean = text.substring(start, end + 1);
  clean = clean.replace(/[\r\n\t]/g, ' ');
  clean = clean.replace(/\\n/g, ' ');
  clean = clean.replace(/\s+/g, ' ');
  clean = clean.replace(/^```json\s*/,'').replace(/```$/,'').trim();
  if (clean.includes('`')) { clean = clean.replace(/`/g, ''); }
  jobs = JSON.parse(clean);
} catch(e) {
  return [{ json: { message: 'Parse error: ' + e.message } }];
}

const filtered = jobs
  .filter(j => j.track !== 'NO FIT' && j.score >= 40)
  .sort((a, b) => b.score - a.score);

if (filtered.length === 0) {
  return [{ json: { message: 'No matches found today.' } }];
}

let msg = 'RaxJobRadar Daily Report\n';
msg += new Date().toLocaleDateString('de-DE') + '\n\n';

filtered.forEach((j, i) => {
  msg += `${i+1}. ${j.title}\n`;
  msg += `Track ${j.track} | Score: ${j.score}/100\n`;
  msg += `${j.reason}\n`;
  msg += `${j.url}\n\n`;
});

msg += `Total: ${filtered.length} matches found.`;
return [{ json: { message: msg } }];
